INSERT INTO `shop_items` VALUES (21,0,0,4,8,NULL,239.00,3.00,NULL,0,1,'addgroup %steamid% beach %var%d',0,1,0,0,1,'[{\"variation_id\": \"7\", \"variation_name\": \"7 days\", \"variation_price\": \"239\", \"variation_price_usd\": \"3\"}]','images/BlB9DqhQh6rvcolWioB0gl4NmuVfrGAD30hBobYH.png',5,1,'Beach','Beach',NULL,NULL,NULL,NULL,NULL,NULL,'Активировать привилегию можно на сайте: \"Мой профиль - Инвентарь - Товары магазинов\" или в игре по команде /store; для получения китов используйте команду /kit','You can activate the privilege on the website: \"My profile - Inventory - Store Products\" or in the game on the command /store; to get whales, use the command /kit',NULL,NULL,NULL,NULL,NULL,'<div class=\"spc__info\">\r\n<div class=\"spc__info--text \">Дополнительные услуги</div>\r\n\r\n<div class=\"spc__info--items\">\r\n<div class=\"spc__info--items__item\">\r\n<div class=\"spc__info----num\">Rate</div>\r\n<img alt=\"spc-img\" src=\"https://rustresort.com/source/2-5.png\" style=\"width: 38px; height: 52px;\" />\r\n<div class=\"spc__info--items__item--help\">Увеличивает рейты добычи ресурсов</div>\r\n</div>\r\n\r\n<div class=\"spc__info--items__item\">\r\n<div class=\"spc__info----num\">SkinBox</div>\r\n<img alt=\"spc-img\" src=\"https://rustresort.com/source/rustresort_icon_skin%20%D0%BA%D0%BE%D0%BF%D0%B8%D1%8F1.png\" style=\"width: 53px; height: 52px;\" />\r\n<div class=\"spc__info--items__item--help\">Позволяет пользоваться привилегией /skinbox</div>\r\n</div>\r\n\r\n<div class=\"spc__info--items__item\">\r\n<div class=\"spc__info----num\">Stamina</div>\r\n<img alt=\"spc-img\" src=\"https://rustresort.com/source/%D0%B8%D0%BC%D0%B5%D0%BD%D0%B8-3.png\" style=\"width: 52px; height: 35px;\" />\r\n<div class=\"spc__info--items__item--help\">Позволяет пользоваться привилегией &quot;Метаболизм&quot; - еда, вода и здоровье после возраждения всегда полные</div>\r\n</div>\r\n\r\n<div class=\"spc__info--items__item\">\r\n<div class=\"spc__info----num\">Vip</div>\r\n<img alt=\