T17llPr89eB7hmoJCddKXQHBmTfApj3GnPWLL.png',3,1,'Nickname','Nickname',NULL,NULL,NULL,NULL,NULL,NULL,'Nickname','Nickname',NULL,NULL,NULL,NULL,NULL,'<style type=\"text/css\">.nickname .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 26px 26px 28px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n  display: flex;\r\n  align-items: flex-start;\r\n  gap: 32px;\r\n  overflow: hidden; /* ограничивает выход изображения за границы */\r\n}\r\n.nickname .ico {\r\n  flex-shrink: 0;\r\n  width: 220px;\r\n  height: 220px;\r\n  border-radius: 16px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n  cursor: zoom-in;\r\n  overflow: hidden;\r\n}\r\n.nickname .ico img {\r\n  width: 160px;\r\n  height: 160px;\r\n  object-fit: contain;\r\n  transition: transform .25s ease;\r\n}\r\n.nickname .ico:hover img {\r\n  transform: scale(1.3);\r\n}\r\n.nickname .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 106%;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.9);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n  z-index: 9999;\r\n}\r\n.nickname .ico:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-4px);\r\n}\r\n.nickname .content {\r\n  display: flex;\r\n  flex-direction: column;\r\n  justify-content: flex-start;\r\n  text-align: left;\r\n}\r\n.nickname .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 10px 0;\r\n}\r\n.nickname .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n  margin-bottom: 8px;\r\n}\r\n.nickname .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"nickname\">\r\n<div class=\"blk\">\r\n<div class=\"ico\"><img alt=\"Цветной ник\" src=\"https://rustresort.com/source/icon/nickname-chat.png\" />\r\n<div class=\"tip\">Цветной ник</div>\r\n</div>\r\n\r\n<div class=\"content\">\r\n<div class=\"ttl\">NICKNAME &mdash; Цветной Ник</div>\r\n\r\n<div class=\"sub\">Услуга моментального действия, активируется сразу после покупки.</div>\r\n\r\n<div class=\"sub\">Позволяет использовать <strong>цветной никнейм</strong> в игровом чате сервера.</div>\r\n</div>\r\n</div>\r\n</div>','<style type=\"text/css\">.nickname .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 26px 26px 28px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n  display: flex;\r\n  align-items: flex-start;\r\n  gap: 32px;\r\n  overflow: hidden; /* ограничивает выход изображения за границы */\r\n}\r\n.nickname .ico {\r\n  flex-shrink: 0;\r\n  width: 220px;\r\n  height: 220px;\r\n  border-radius: 16px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n  cursor: zoom-in;\r\n  overflow: hidden;\r\n}\r\n.nickname .ico img {\r\n  width: 160px;\r\n  height: 160px;\r\n  object-fit: contain;\r\n  transition: transform .25s ease;\r\n}\r\n.nickname .ico:hover img {\r\n  transform: scale(1.3);\r\n}\r\n.nickname .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 106%;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.9);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n  z-index: 9999;\r\n}\r\n.nickname .ico:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-4px);\r\n}\r\n.nickname .content {\r\n  display: flex;\r\n  flex-direction: column;\r\n  justify-content: flex-start;\r\n  text-align: left;\r\n}\r\n.nickname .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 10px 0;\r\n}\r\n.nickname .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n  margin-bottom: 8px;\r\n}\r\n.nickname .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"nickname\">\r\n<div class=\"blk\">\r\n<div class=\"ico\"><img alt=\"Nickname\" src=\"https://rustresort.com/source/icon/nickname-chat.png\" />\r\n<div class=\"tip\">Colored Nickname</div>\r\n</div>\r\n\r\n<div class=\"content\">\r\n<div class=\"ttl\">NICKNAME &mdash; Colored Name</div>\r\n\r\n<div class=\"sub\">Instant activation service, applied automatically after purchase.</div>\r\n\r\n<div class=\"sub\">Allows you to use a <strong>colored nickname</strong> in the in-game chat.</div>\r\n</div>\r\n</div>\r\n</div>',NULL,NULL,NULL,NULL,NULL,'2026-02-01 11:48:00','2026-02-01 11:48:00'),(210,0,0,13,8,NULL,249.00,3.00,NULL,0,1,NULL,0,1,0,0,1,'[]','images/11Tge0iuWN3AQCRvY6dgn1vaXzRFtpsWsjaXlI4t.jpg',777111,1,'Tool Cupboard','Tool Cupboard',NULL,NULL,NULL,NULL,NULL,NULL,'Скин на холодильник','Tool Cupboard',NULL,NULL,NULL,NULL,NULL,'<p><img alt=\"\" src=\"https://rustresort.com/source/%D0%BD%D0%B0%D0%B7%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F%20(5).jpg\" style=\"width: 960px; height: 540px;\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://rustresort.com/source/%D0%BD%D0%B0%D0%B7%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F.jpg\" style=\"width: 960px; height: 540px;\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://rustresort.com/source/%D0%BD%D0%B0%D0%B7%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F%20(1).jpg\" style=\"width: 960px; height: 540px;\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://rustresort.com/source/%D0%BD%D0%B0%D0%B7%D0%B2%D0%B0%D0%BD%D0%B8%D1%8F%20(2).jpg\" style=\"width: 960px; height: 540px;\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https