6','2026-01-31 06:43:36'),(251,0,0,4,2,'[\"2\",\"3\"]',599.00,8.00,30.00,1,1,'grantperm %steamid% rate.vip %var%d',0,1,0,0,1,'[{\"variation_id\":\"7\",\"variation_name\":\"7 days\",\"variation_price\":\"599\",\"variation_price_usd\":\"8\"},{\"variation_id\":\"30\",\"variation_name\":\"30 days\",\"variation_price\":\"1790\",\"variation_price_usd\":\"22\"},{\"variation_id\":\"90\",\"variation_name\":\"90 days\",\"variation_price\":\"3690\",\"variation_price_usd\":\"47\"}]','images/eMDWUR2OdFzJS0MCKqvINdItTLBJTi125mz2Lf9z.png',1,1,'Rate X3','Rate X3',NULL,NULL,NULL,NULL,NULL,NULL,'Rate X3','Rate X3',NULL,NULL,NULL,NULL,NULL,'<style type=\"text/css\">.rate-x3 .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 18px 22px 20px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n  margin-bottom: 16px;\r\n}\r\n.rate-x3 .hdr {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 6px;\r\n}\r\n.rate-x3 .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0;\r\n}\r\n.rate-x3 .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.5;\r\n}\r\n.rate-x3 .grid {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  gap: 12px;\r\n  margin-top: 10px;\r\n}\r\n.rate-x3 .it {\r\n  width: 72px;\r\n  height: 72px;\r\n  border-radius: 10px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n  transition: transform .15s ease;\r\n}\r\n.rate-x3 .it:hover {\r\n  transform: scale(1.05);\r\n}\r\n.rate-x3 .it img {\r\n  width: 46px;\r\n  height: 46px;\r\n  object-fit: contain;\r\n  filter: drop-shadow(0 1px 1px rgba(0,0,0,.35));\r\n}\r\n.rate-x3 .q {\r\n  position: absolute;\r\n  right: 6px;\r\n  bottom: 6px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  color: #ddd;\r\n  background: rgba(0,0,0,.4);\r\n  padding: 2px 6px;\r\n  border-radius: 6px;\r\n}\r\n.rate-x3 .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 82px;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.9);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n  z-index: 9999;\r\n}\r\n.rate-x3 .it:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-2px);\r\n}\r\n</style>\r\n<div class=\"rate-x3\">\r\n<div class=\"blk\">\r\n<div class=\"hdr\">\r\n<div class=\"ttl\">Привилегия X3 &mdash; Фарм Ресурсов</div>\r\n\r\n<div class=\"sub\"><strong>Список ресурсов, добываемых X3:</strong><br />\r\nДерево, Камень, Железо, Сера, Ткань, добыча от разделки животных и прочий сбор ресурсов.</div>\r\n</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:16px;\"><strong>Пример количества ресурсов за 1 добычу:</strong></div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img alt=\"stone\" src=\"https://rustresort.com/source/icon/stones.png\" />\r\n<div class=\"q\">x3000</div>\r\n\r\n<div class=\"tip\">Камень</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"metal-ore\" src=\"https://rustresort.com/source/icon/metal-ore.png\" />\r\n<div class=\"q\">x1800</div>\r\n\r\n<div class=\"tip\">Железо</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"sulfur-ore\" src=\"https://rustresort.com/source/icon/sulfur-ore.png\" />\r\n<div class=\"q\">x900</div>\r\n\r\n<div class=\"tip\">Сера</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"cloth\" src=\"https://rustresort.com/source/icon/cloth.png\" />\r\n<div class=\"q\">x30</div>\r\n\r\n<div class=\"tip\">Ткань</div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:18px;\">Не влияет на: <em>компоненты, ящики, дизель</em> и другие источники лута.</div>\r\n</div>\r\n</div>','<style type=\"text/css\">.rate-x3 .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 18px 22px 20px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n  margin-bottom: 16px;\r\n}\r\n.rate-x3 .hdr {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 6px;\r\n}\r\n.rate-x3 .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0;\r\n}\r\n.rate-x3 .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.5;\r\n}\r\n.rate-x3 .grid {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  gap: 12px;\r\n  margin-top: 10px;\r\n}\r\n.rate-x3 .it {\r\n  width: 72px;\r\n  height: 72px;\r\n  border-radius: 10px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n  transition: transform .15s ease;\r\n}\r\n.rate-x3 .it:hover {\r\n  transform: scale(1.05);\r\n}\r\n.rate-x3 .it img {\r\n  width: 46px;\r\n  height: 46px;\r\n  object-fit: contain;\r\n  filter: drop-shadow(0 1px 1px rgba(0,0,0,.35));\r\n}\r\n.rate-x3 .q {\r\n  position: absolute;\r\n  right: 6px;\r\n  bottom: 6px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  color: #ddd;\r\n  background: rgba(0,0,0,.4);\r\n  padding: 2px 6px;\r\n  border-radius: 6px;\r\n}\r\n.rate-x3 .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 82px;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.9);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n  z-index: 9999;\r\n}\r\n.rate-x3 .it:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-2px);\r\n}\r\n</style>\r\n<div class=\"rate-x3\">\r\n<div class=\"blk\">\r\n<div class=\"hdr\">\r\n<div class=\"ttl\">Rate X3 &mdash; Resource Farming</div>\r\n\r\n<div class=\"sub\"><strong>List of resources affected by X3:</strong><br />\r\nWood, Stone, Metal, Sulfur, Cloth, animal harvesting and other resource gathering.</div>\r\n</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:16px;\"><strong>Example of resources per one gathering:</strong></div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img alt=\"stone\" src=\"https://rustresort.com/source/icon/stones.png\" />\r\n<div class=\"q\">x3000</div>\r\n\r\n<div class=\"tip\">Stone</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"metal-ore\" src=\"https://rustresort.com/source/icon/metal-ore.png\" />\r\n<div class=\"q\">x1800</div>\r\n\r\n<div class=\"tip\">Metal Ore</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"sulfur-ore\" src=\"https://rustresort.com/source/icon/sulfur-ore.png\" />\r\n<div class=\"q\">x900</div>\r\n\r\n<div class=\"tip\">Sulfur Ore</div>\r\n</div>\r\n\r\n<div class=\"it\"><img alt=\"cloth\" src=\"https://rustresort.com/source/icon/cloth.png\" />\r\n<div class=\"q\">x30</div>\r\n\r\n<div class=\"tip\">Cloth</div>\r\n</div>\r\n</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:18px;\">Does not affect: <em>components, crates, diesel</em> and other loot sources.</div>\r\n</div>\r\n</div>',NULL,NULL,NULL,NULL,NULL,'2026-02-23 07:55:09','2026-02-23 07:55:09'),(253,9991,9991,4,2,'[\"2\",\"3\"]',349.00,5.00,NULL,1,1,'addgroup %steamid% vip %var%d',0,1,0,0,1,'[{\"variation_id\":\"6\",\"variation_name\":\"6 days\",\"variation_price\":\"349\",\"variation_price_usd\":\"5\"},{\"variation_id\":\"30\",\"variation_name\":\"30 days\",\"variation_price\":\"990\",\"variation_price_usd\":\"12.5\"}]','images/VIYQDFxegMV1RcDC2qV2fhriTB6DeIMiWXFadmze.png',-4,1,'VIP','VIP','VIP','VIP','VIP','VIP','VIP',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'<style type=\"text/css\">.vip .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 26px 26px 28px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n}\r\n.vip .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 12px 0;\r\n}\r\n.vip .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n}\r\n.vip .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"vip\">\r\n<div class=\"blk\">\r\n<div class=\"ttl\">VIP &mdash; Пропуск Очереди</div>\r\n\r\n<div class=\"sub\">Дает возможность подключаться к серверу <strong>без ожидания в очереди</strong>.</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:12px;\">После покупки просто переподключитесь к серверу, чтобы пропустить очередь и войти мгновенно.</div>\r\n</div>\r\n</div>','<style type=\"text/css\">.vip .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 26px 26px 28px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n}\r\n.vip .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 12px 0;\r\n}\r\n.vip .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n}\r\n.vip .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"vip\">\r\n<div class=\"blk\">\r\n<div class=\"ttl\">VIP &mdash; Queue Skip</div>\r\n\r\n<div class=\"sub\">Grants the ability to join the server <strong>without waiting in the queue</strong>.</div>\r\n\r\n<div class=\"sub\" style=\"margin-top:12px;\">After purchase, simply reconnect to the server to skip the queue and join instantly.</div>\r\n</div>\r\n</div>',NULL,NULL,NULL,NULL,NULL,'2026-02-01 11:47:45','2026-02-01 11:47:45'),(254,0,9991,4,-1,'[null, null, null, null]',399.00,5.00,NULL,0,1,'addgroup %steamid% vip %var%d',0,1,0,0,1,'[{\"variation_id\": \"7\", \"variation_name\": \"7 days\", \"variation_price\": \"399\", \"variation_price_usd\": \"5\"}]','images/k25ZjsUfOWAU4lyfCG6GBg5dtV1YAsdkCLzj7WB5.png',666113,1,'MAIN ELITE','MAIN ELITE',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'<p>Данная стоимость будет на время проведения ивента</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>1. Позволяет подключаться к серверу без очереди.</p>\r\n\r\n<p>2. Ваш никнейм будет выделен золотым цветом</p>\r\n\r\n<p>После покупки - переподключитесь к серверу, чтобы зайти без очереди</p>','<p>Allows you to connect to the server without a queue.</p>\r\n\r\n<p>Your nickname will be highlighted in gold</p>\r\n\r\n<p>After purchase, reconnect to the server to log in without a queue</p>',NULL,NULL,NULL,NULL,NULL,'2024-03-14 13:47:39','2024-03-14 13:47:39'),(277,0,0,2,-1,'[null, null, null]',10.00,1.00,NULL,0,1,NULL,0,0,0,0,1,'[]','images/8EEOpJwpHzY5bb7jsp86WnwY3PrsdIiMBCiNOPYB.png',30650,0,'Hat wolf','Hat wolf',NULL,NULL,NULL,NULL,NULL,'hat.wolf',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2024-05-19 10:04:15','2024-05-19 10:04:15'),(278,0,0,2,-1,'[null, null, null]',10.00,1.00,NULL,0,1,NULL,0,0,0,0,1,'[]','images/132XjwvnYMKXOxusc3GThO0q1TxKgnwE7VFhm3Cx.png',30660,0,'Poncho','Poncho',NULL,NULL,NULL,NULL,NULL,'attire.hide.poncho',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2024-05-19 11:18:45','2024-05-19 11:18:45'),(279,0,0,2,-1,'[null, null, null]',10.00,1.00,NULL,0,1,NULL,0,0,0,0,1,'[]','images/Uk8qBE76yaIckZdnLckaqsYhrj537u35pdZxjeJR.png',30665,0,'Pants','Pants',NULL,NULL,NULL,NULL,NULL,'attire.hide.pants',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2024-05-19 11:19:13','2024-05-19 11:19:13'),(280,0,0,2,-1,'[null, null, null]',10.00,1.00,NULL,0,1,NULL,0,0,0,0,1,'[]','images/EY7frWQUn6OEgMdrK3wWKvl4fm5tG65C4yv32X8m.png',30670,0,'Boots','Boots',NULL,NULL,NULL,NULL,NULL,'attire.hide.boots',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'2024-05-19 11:19:31','2024-05-19 11:19:31'),(282,0,0,7,-1,'[null, null, null]',5.00,1.00,NULL,0,1,NULL,0,0,0,0,1,'[]','images/LTQrz6WQzcMhUxANlb1wu2mwlYhrRd9lDyZ5Wy5D.png',8350,0,'Arrow wooden','Arrow wooden',NULL,NULL,NULL,NULL,NULL,'arrow.wooden',