content {\r\n  display: flex;\r\n  flex-direction: column;\r\n  justify-content: flex-start;\r\n  text-align: left;\r\n}\r\n.blueprint .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 10px 0;\r\n}\r\n.blueprint .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n  margin-bottom: 8px;\r\n}\r\n.blueprint .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"blueprint\">\r\n<div class=\"blk\">\r\n<div class=\"ico\"><img alt=\"Blueprints\" src=\"https://rustresort.com/source/icon/Blueprints.png\" />\r\n<div class=\"tip\">Все чертежи</div>\r\n</div>\r\n\r\n<div class=\"content\">\r\n<div class=\"ttl\">BLUEPRINT &mdash; Все Чертежи</div>\r\n\r\n<div class=\"sub\">Услуга моментального действия.<br />\r\nПосле покупки &mdash; просто переподключитесь к серверу, и все изученные предметы сразу появятся в окне крафта.</div>\r\n\r\n<div class=\"sub\">После активации вам доступны для крафта <strong>все предметы, оружие и электроника</strong> на сервере.<br />\r\nНе включены DLC-предметы и платные косметические наборы.</div>\r\n</div>\r\n</div>\r\n</div>','<style type=\"text/css\">.blueprint .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 26px 26px 28px;\r\n  border-radius: 12px;\r\n  background: rgba(10,10,10,.65);\r\n  backdrop-filter: blur(12px) contrast(1.2);\r\n  display: flex;\r\n  align-items: flex-start;\r\n  gap: 28px;\r\n}\r\n.blueprint .ico {\r\n  flex-shrink: 0;\r\n  width: 120px;\r\n  height: 120px;\r\n  border-radius: 14px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n  transition: transform .15s ease;\r\n}\r\n.blueprint .ico:hover {\r\n  transform: scale(1.05);\r\n}\r\n.blueprint .ico img {\r\n  width: 86px;\r\n  height: 86px;\r\n  object-fit: contain;\r\n  filter: drop-shadow(0 1px 1px rgba(0,0,0,.35));\r\n}\r\n.blueprint .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 106px;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.9);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n  z-index: 9999;\r\n}\r\n.blueprint .ico:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-2px);\r\n}\r\n.blueprint .content {\r\n  display: flex;\r\n  flex-direction: column;\r\n  justify-content: flex-start;\r\n  text-align: left;\r\n}\r\n.blueprint .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9f1c;\r\n  text-transform: uppercase;\r\n  margin: 0 0 10px 0;\r\n}\r\n.blueprint .sub {\r\n  font-size: 15px;\r\n  color: #ccc;\r\n  line-height: 1.6;\r\n  margin-bottom: 8px;\r\n}\r\n.blueprint .sub strong {\r\n  color: #fff;\r\n}\r\n</style>\r\n<div class=\"blueprint\">\r\n<div class=\"blk\">\r\n<div class=\"ico\"><img alt=\"Blueprints\" src=\"https://rustresort.com/source/icon/Blueprints.png\" />\r\n<div class=\"tip\">All Blueprints</div>\r\n</div>\r\n\r\n<div class=\"content\">\r\n<div class=\"ttl\">BLUEPRINT &mdash; All Blueprints</div>\r\n\r\n<div class=\"sub\">Instant activation service.<br />\r\nAfter purchase, simply reconnect to the server &mdash; all learned items will immediately appear in your crafting menu.</div>\r\n\r\n<div class=\"sub\">Once activated, you gain access to craft <strong>all items, weapons, and electronics</strong> available on the server.<br />\r\nDLC-exclusive items and paid cosmetic sets are not included.</div>\r\n</div>\r\n</div>\r\n</div>',NULL,NULL,NULL,NULL,NULL,'2026-02-23 07:55:03','2026-02-23 07:55:03'),(298,0,0,4,0,'[null,null]',825.00,10.00,30.00,0,1,'addgroup %steamid% OUTPOST %var%d',0,1,0,0,1,'[{\"variation_id\":\"6\",\"variation_name\":\"6 days\",\"variation_price\":\"825,00\",\"variation_price_usd\":\"10\"},{\"variation_id\":\"30\",\"variation_name\":\"30 days\",\"variation_price\":\"2475,00\",\"variation_price_usd\":\"30\"}]','images/2lNfmPiOL8HHGLjWJZyF108aRmsgZfVTFpvyJQYQ.png',-7,1,'Outpost KIT','Outpost KIT',NULL,NULL,NULL,NULL,NULL,NULL,'После покупки набор активируется мгновенно. Для получения предметов на сервере воспользуйтесь командой /kit в игровом чате.','Once purchased, this kit will be instantly activated on your account. Use the in-game command /kit to collect your items.',NULL,NULL,NULL,NULL,NULL,'<!-- OUTPOST KIT — РУССКАЯ ФИНАЛЬНАЯ ВЕРСИЯ -->\r\n<style type=\"text/css\">.outpost-kit .blk {\r\n  border-bottom: 1px solid rgba(255,255,255,.08);\r\n  padding: 18px 22px 20px;\r\n  border-radius: 12px;\r\n  background: rgba(15,15,15,.55);\r\n  backdrop-filter: blur(14px) contrast(1.25);\r\n  margin-bottom: 16px;\r\n  position: relative;\r\n  overflow: visible;\r\n}\r\n.outpost-kit .hdr {\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  margin-bottom: 10px;\r\n}\r\n.outpost-kit .ttl {\r\n  font-size: 22px;\r\n  font-weight: 800;\r\n  color: #ff9800;\r\n  text-transform: uppercase;\r\n  letter-spacing: .5px;\r\n  margin: 0;\r\n}\r\n.outpost-kit .meta {\r\n  font-size: 14px;\r\n  color: #ccc;\r\n}\r\n.outpost-kit .meta span {\r\n  color: #ff9800;\r\n  font-weight: 700;\r\n  margin: 0 8px;\r\n}\r\n.outpost-kit .grid {\r\n  display: flex;\r\n  flex-wrap: wrap;\r\n  gap: 12px;\r\n  justify-content: flex-start;\r\n}\r\n.outpost-kit .it {\r\n  width: 72px;\r\n  height: 72px;\r\n  border-radius: 10px;\r\n  background: rgba(20,20,20,.55);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  position: relative;\r\n}\r\n.outpost-kit .it img {\r\n  width: 46px;\r\n  height: 46px;\r\n  object-fit: contain;\r\n  filter: drop-shadow(0 1px 1px rgba(0,0,0,.35));\r\n}\r\n.outpost-kit .q {\r\n  position: absolute;\r\n  right: 6px;\r\n  bottom: 6px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  color: #ddd;\r\n  background: rgba(0,0,0,.4);\r\n  padding: 2px 6px;\r\n  border-radius: 6px;\r\n}\r\n.outpost-kit .tip {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 82px;\r\n  transform: translateX(-50%);\r\n  background: rgba(0,0,0,.90);\r\n  color: #fff;\r\n  border-radius: 6px;\r\n  padding: 6px 10px;\r\n  font-size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  z-index: 9999;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n}\r\n.outpost-kit .it:hover .tip,\r\n.outpost-kit .svc-ico:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-2px);\r\n}\r\n.outpost-kit .svc .grid {\r\n  justify-content: flex-start;\r\n  gap: 28px;\r\n  padding: 12px 0 8px;\r\n}\r\n.outpost-kit .svc-card {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  gap: 8px;\r\n  position: relative;\r\n}\r\n.outpost-kit .svc-ico {\r\n  width: 100px;\r\n  height: 100px;\r\n  border-radius: 14px;\r\n  background: rgba(255,255,255,.05);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  transition: box-shadow .2s ease, transform .2s ease;\r\n  position: relative;\r\n}\r\n.outpost-kit .svc-ico:hover {\r\n  box-shadow: 0 0 20px rgba(255,255,255,.25);\r\n  transform: scale(1.03);\r\n}\r\n.outpost-kit .svc-ico img {\r\n  width: 86px;\r\n  height: 86px;\r\n  object-fit: contain;\r\n}\r\n.outpost-kit .svc-lbl {\r\n  font-size: 14px;\r\n  font-weight: 700;\r\n  color: #fff;\r\n  text-align: center;\r\n  opacity: .95;\r\n}\r\n</style>\r\n<div class=\"outpost-kit\"><!-- ? ДОПОЛНИТЕЛЬНЫЕ УСЛУГИ -->\r\n<div class=\"blk svc\">\r\n<div class=\"hdr\">\r\n<div class=\"ttl\">ДОПОЛНИТЕЛЬНЫЕ УСЛУГИ</div>\r\n\r\n<div class=\"meta\" style=\"color:#ff9800;\">Активируются с покупкой</div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"svc-card\">\r\n<div class=\"svc-ico\"><img alt=\"nickname\" src=\"https://rustresort.com//storage/images/YT0vgerJMGe2ihzDchbquSG1ow4EmFi5ZYJIuAf4.png\" />\r\n<div