size: 12px;\r\n  font-weight: 700;\r\n  white-space: nowrap;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  z-index: 9999;\r\n  transition: opacity .15s ease, transform .15s ease;\r\n}\r\n.military-kit .it:hover .tip,\r\n.military-kit .svc-ico:hover .tip {\r\n  opacity: 1;\r\n  transform: translateX(-50%) translateY(-2px);\r\n}\r\n.military-kit .svc .grid {\r\n  justify-content: flex-start;\r\n  gap: 28px;\r\n  padding: 12px 0 8px;\r\n}\r\n.military-kit .svc-card {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  gap: 8px;\r\n  position: relative;\r\n}\r\n.military-kit .svc-ico {\r\n  width: 100px;\r\n  height: 100px;\r\n  border-radius: 14px;\r\n  background: rgba(255,255,255,.05);\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  transition: box-shadow .2s ease, transform .2s ease;\r\n  position: relative;\r\n}\r\n.military-kit .svc-ico:hover {\r\n  box-shadow: 0 0 20px rgba(255,255,255,.25);\r\n  transform: scale(1.03);\r\n}\r\n.military-kit .svc-ico img {\r\n  width: 86px;\r\n  height: 86px;\r\n  object-fit: contain;\r\n}\r\n.military-kit .svc-lbl {\r\n  font-size: 14px;\r\n  font-weight: 700;\r\n  color: #fff;\r\n  text-align: center;\r\n  opacity: .95;\r\n}\r\n</style>\r\n<div class=\"military-kit\"><!-- ? ADDITIONAL SERVICES -->\r\n<div class=\"blk svc\">\r\n<div class=\"hdr\">\r\n<div class=\"ttl\">ADDITIONAL SERVICES</div>\r\n\r\n<div class=\"meta\" style=\"color:#ff9800;\">Activated upon purchase</div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"svc-card\">\r\n<div class=\"svc-ico\"><img alt=\"nickname\" src=\"https://rustresort.com//storage/images/YT0vgerJMGe2ihzDchbquSG1ow4EmFi5ZYJIuAf4.png\" />\r\n<div class=\"tip\">Nickname &mdash; yellow color in chat</div>\r\n</div>\r\n\r\n<div class=\"svc-lbl\">Nickname</div>\r\n</div>\r\n\r\n<div class=\"svc-card\">\r\n<div class=\"svc-ico\"><img alt=\"vip\" src=\"https://rustresort.com//storage/images/VIYQDFxegMV1RcDC2qV2fhriTB6DeIMiWXFadmze