class=\"ttl\">СНАРЯЖЕНИЕ / МОДИФИКАЦИИ</div>\r\n\r\n<div class=\"meta\">WipeBlock: <span>2ч</span> | CoolDown: <span>12ч</span></div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/largebackpack.png\" />\r\n<div class=\"tip\">Военный рюкзак</div>\r\n</div>\r\n\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/weapon-mod-holosight.png\" />\r\n<div class=\"tip\">Голографический прицел</div>\r\n</div>\r\n\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/weapon-mod-silencer.png\" />\r\n<div class=\"tip\">Глушитель</div>\r\n</div>\r\n\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/weapon-mod-lasersight.png\" />\r\n<div class=\"tip\">Лазерный прицел</div>\r\n</div>\r\n</div>\r\n</div>\r\n<!-- ? ПРОЧЕЕ -->\r\n\r\n<div class=\"blk\">\r\n<div class=\"hdr\">\r\n<div class=\"ttl\">ПРОЧЕЕ</div>\r\n\r\n<div class=\"meta\">WipeBlock: <span>2h</span> | CoolDown: <span>12h</span></div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/pureoretea.png\" />\r\n<div class=\"q\">x2</div>\r\n\r\n<div class=\"tip\">Pure Ore Tea</div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/purewoodtea.png\" />\r\n<div class=\"q\">x2</div>\r\n\r\n<div class=\"tip\">Pure Wood Tea</div>\r\n</div>\r\n\r\n<div class=\"tip\">Pure Ore Tea</div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/bearpie.png\" />\r\n<div class=\"q\">x2</div>\r\n\r\n<div class=\"tip\">Bear Pie</div>\r\n</div>\r\n\r\n<div class=\"grid\">\r\n<div class=\"it\"><img src=\"https://rustresort.com/source/icon/supply-signal.png\" />\r\n<div class=\"q\">x1</div>\r\n\r\n<div class=\"tip\">Airdrop (Supply Signal)</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','<!-- ? COBALT KIT — FINAL ENGLISH VERSION -->\r\n<style type=\"text/css\">.cobalt-kit .blk{border-bottom:1px solid rgba(255,255,255,.08);padding:18px 22px 20px;border-radius:12px;background:rgba(15,15,15,.55);backdrop-filter:blur(14px) contrast(1.25);margin-bottom:16px;position:relative;overflow:visible}\r\n.cobalt-kit .hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:10px}\r\n.cobalt-kit .ttl{font-size:22px;font-weight:800;color:#ff9800;text-transform:uppercase;letter-spacing:.5px;margin:0}\r\n.cobalt-kit .meta{font-size:14px;color:#ccc}\r\n.cobalt-kit .meta span{color:#ff9800;font-weight:700;margin:0 8px}\r\n.cobalt-kit .grid{display:flex;flex-wrap:wrap;gap:12px;justify-content:flex-start}\r\n.cobalt-kit .it{width:72px;height:72px;border-radius:10px;background:rgba(20,20,20,.55);display:flex;align-items:center;justify-content:center;position:relative}\r\n.cobalt-kit .it img{width:46px;height:46px;object-fit:contain;filter:drop-shadow(0 1px 1px rgba(0,0,0,.35))}\r\n.cobalt-kit .q{position:absolute;right:6px;bottom:6px;font-size:12px;font-weight:700;color:#ddd;background:rgba(0,0,0,.4);padding:2px 6px;border-radius:6px}\r\n.cobalt-kit .tip{position:absolute;left:50%;bottom:82px;transform:translateX(-50%);background:rgba(0,0,0,.90);color:#fff;border-radius:6px;padding:6px 10px;font-size:12px;font-weight:700;white-space:nowrap;opacity:0;pointer-events:none;z-index:9999;transition:opacity .15s ease, transform .15s ease}\r\n.cobalt-kit .it:hover .tip,.cobalt-kit .svc-ico:hover .tip{opacity:1;transform:translateX(-50%) translateY(-2px)}\r\n.cobalt-kit .svc .grid{justify-content:flex-start;gap:28px;padding:12px 0 8px}\r\n.cobalt-kit .svc-card{display:flex;flex-direction:column;align-items:center;gap:8px;position:relative}\r\n.cobalt-kit .svc-ico{width:100px;height:100px;border-radius:14px;background:rgba(255,255,255,.05);display:flex;align-items:center;justify-content:center;transition:box-shadow .2s ease, transform .2s ease;position:relative}\r\n.cobalt-kit .svc-ico:hover{box-shadow:0 0 20px rgba(255,255,255,.25);transfo